import java.util.Scanner;

public class SecureBufferExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Limiting the input size to prevent buffer overflow
        if (name.length() > 10) {
            System.out.println("Input size exceeds limit. Please enter a name with 10 characters or less.");
            return;
        }

        char[] buffer = new char[10];
        name.getChars(0, Math.min(name.length(), 10), buffer, 0);

        // Accessing the array element within its bounds
        System.out.println("Hello, " + buffer[0]);
    }
}

### Explanation:
취약유형: Buffer Overflow
